{
var seed = GetInt(parameters, "seed", context.Seed);
var scale = GetFloat(parameters, "scale", 2.5f);
var flowSpeed = GetFloat(parameters, "flowSpeed", 0.4f);
var flowAngle = GetFloat(parameters, "flowAngle", 0f);
var glowIntensity = GetFloat(parameters, "glowIntensity", 0.7f);
var veinDensity = GetFloat(parameters, "veinDensity", 0.5f);
var lavaColor = GetColor(parameters, "lavaColor", Color.FromRgb(255, 120, 20));
var hotColor = GetColor(parameters, "hotColor", Color.FromRgb(255, 220, 80));
var crustColor = GetColor(parameters, "crustColor", Color.FromRgb(35, 25, 20));
var emberAmount = GetFloat(parameters, "emberAmount", 0.3f);
var octaves = Math.Max(1, GetInt(parameters, "octaves", 3));
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var lR = lavaColor.R / 255f; var lG = lavaColor.G / 255f; var lB = lavaColor.B / 255f;
var hR = hotColor.R / 255f; var hG = hotColor.G / 255f; var hB = hotColor.B / 255f;
var cR = crustColor.R / 255f; var cG = crustColor.G / 255f; var cB = crustColor.B / 255f;

var angleRad = flowAngle * MathF.PI / 180f;
var cosA = MathF.Cos(angleRad);
var sinA = MathF.Sin(angleRad);

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Flow-aligned coordinates
    var flowU = u * cosA - v * sinA;
    var flowV = u * sinA + v * cosA;

    // Flow distortion
    var distort = TileableFractalNoise(u * scale * 0.5f, v * scale * 0.5f,
        Math.Max(1, (int)MathF.Round(scale * 0.5f)), 2, 0.5f, 2f, seed);
    var du = flowU + distort * flowSpeed * 0.2f;
    var dv = flowV + distort * flowSpeed * 0.15f;

    // Multi-octave lava noise
    var lavaNoise = TileableFractalNoise(du * scale, dv * scale,
        Math.Max(1, (int)MathF.Round(scale)), octaves, 0.55f, 2.2f, seed + 100);

    // Streak noise (elongated along flow direction)
    var streakNoise = TileableFractalNoise(
        du * scale * 1.2f, dv * scale * 3f,
        Math.Max(1, (int)MathF.Round(scale * 3f)), octaves - 1, 0.5f, 2f, seed + 200);

    // Combine for flow texture
    var flowTex = lavaNoise * 0.7f + streakNoise * 0.3f;

    // Crack pattern (high-frequency detail)
    var crackNoise = TileableFractalNoise(
        u * scale * 4f, v * scale * 4f,
        Math.Max(1, (int)MathF.Round(scale * 4f)), 2, 0.5f, 2.5f, seed + 300);

    // Detect cracks: sharp transitions
    var crackEdge = MathF.Abs(crackNoise - 0.5f) * 2f;
    crackEdge = MathF.Pow(crackEdge, 2f);

    // Glowing fissures where noise crosses threshold
    var fissure = MathF.Max(0f, crackEdge - (1f - veinDensity * 0.8f));
    fissure = MathF.Pow(fissure, 1.5f) * glowIntensity;

    // Embers — small bright spots
    var emberNoise = TileableFractalNoise(
        u * scale * 8f + 100f, v * scale * 8f + 100f,
        Math.Max(1, (int)MathF.Round(scale * 8f)), 1, 0.5f, 2f, seed + 400);
    var ember = MathF.Max(0f, (emberNoise - 0.85f) / 0.15f) * emberAmount;

    // Cooling crust: areas of low flowTex
    var crustAmount = 1f - flowTex;
    var isCrust = crustAmount > 0.5f + veinDensity * 0.2f;

    float r, g, b;

    if (isCrust)
    {
        // Dark crust with subtle glow from underneath
        var crustStrength = (crustAmount - 0.5f - veinDensity * 0.2f) / (0.5f - veinDensity * 0.2f);
        crustStrength = Math.Clamp(crustStrength, 0f, 1f);

        // Crack glow showing through crust
        var crackGlow = fissure * (1f - crustStrength * 0.7f);

        r = Lerp(lR, cR, crustStrength) + crackGlow * 0.5f;
        g = Lerp(lG * 0.6f, cG, crustStrength) + crackGlow * 0.3f;
        b = Lerp(lB * 0.2f, cB, crustStrength);
    }
    else
    {
        // Exposed lava
        var hotFactor = flowTex;

        // Core glow: brightest in center, fading at edges
        var coreGlow = (1f - crustAmount * 2f) * glowIntensity;
        coreGlow = Math.Clamp(coreGlow, 0f, 1f);

        r = Lerp(lR, hR, hotFactor * 0.8f + coreGlow * 0.2f);
        g = Lerp(lG * 0.7f, hG, hotFactor * 0.6f + coreGlow * 0.4f);
        b = Lerp(lB * 0.3f, hB * 0.5f, hotFactor * 0.4f + coreGlow * 0.6f);
    }

    // Add fissure glow on top
    if (fissure > 0.05f)
    {
        var fissureGlow = fissure * glowIntensity;
        r = Lerp(r, hR, fissureGlow * 0.7f);
        g = Lerp(g, hG, fissureGlow * 0.8f);
        b = Lerp(b, hB * 0.7f, fissureGlow);
    }

    // Add ember sparks
    if (ember > 0.01f)
    {
        r = Math.Clamp(r + ember * 0.8f, 0f, 1f);
        g = Math.Clamp(g + ember * 0.6f, 0f, 1f);
        b = Math.Clamp(b + ember * 0.3f, 0f, 1f);
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
